#include<stdio.h>
#define N 100001
int ch[N][2],nc[N],dep[N],q[N];
int main(){int n;scanf("%d",&n);for(int i=0;i<n;i++)nc[i]=0;int root=0;for(int i=0;i<n;i++){int p;scanf("%d",&p);if(p<0)root=i;else{ch[p][nc[p]++]=i;}}int front=0,back=0;q[back++]=root;dep[root]=0;int ans=0;while(front<back){int u=q[front++];if(dep[u]>ans)ans=dep[u];for(int j=0;j<nc[u];j++){dep[ch[u][j]]=dep[u]+1;q[back++]=ch[u][j];}}printf("%d\n",ans);}
